--- a/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
+++ b/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
@@ -5541,10 +5541,120 @@ static void createUnreachableSwitchDefault(SwitchInst *Switch,
 /// Turn a switch into an integer range comparison and branch.
 /// Switches with more than 2 destinations are ignored.
 /// Switches with 1 destination are also ignored.
+static bool foldSwitchOnCmpIntrinsic(SwitchInst *SI, IRBuilder<> &Builder) {
+  // Check if the switch condition is a ucmp or scmp intrinsic.
+  // ucmp/scmp return -1, 0, or 1 depending on the comparison result.
+  // If the switch distinguishes these ranges, we can optimize it to a
+  // direct comparison of the operands.
+  Value *Cond = SI->getCondition();
+  auto *II = dyn_cast<IntrinsicInst>(Cond);
+  if (!II)
+    return false;
+
+  Intrinsic::ID IID = II->getIntrinsicID();
+  if (IID != Intrinsic::ucmp && IID != Intrinsic::scmp)
+    return false;
+
+  // Partition the cases into two sets with different destinations.
+  BasicBlock *DestA = SI->getDefaultDest();
+  BasicBlock *DestB = nullptr;
+  SmallVector<ConstantInt *, 16> CasesA;
+  SmallVector<ConstantInt *, 16> CasesB;
+
+  for (auto Case : SI->cases()) {
+    BasicBlock *Dest = Case.getCaseSuccessor();
+    if (!DestA)
+      DestA = Dest;
+    if (Dest == DestA) {
+      CasesA.push_back(Case.getCaseValue());
+      continue;
+    }
+    if (!DestB)
+      DestB = Dest;
+    if (Dest == DestB) {
+      CasesB.push_back(Case.getCaseValue());
+      continue;
+    }
+    return false; // More than two destinations.
+  }
+  if (!DestB)
+    return false; // All destinations are the same
+  if (CasesA.size() + CasesB.size() != SI->getNumCases())
+    return false;
+
+  bool IsSigned = (IID == Intrinsic::scmp);
+  Value *LHS = II->getOperand(0);
+  Value *RHS = II->getOperand(1);
+
+  // Collect all case values for each destination
+  SmallVector<APInt, 3> ValuesA, ValuesB;
+  for (auto *C : CasesA)
+    ValuesA.push_back(C->getValue());
+  for (auto *C : CasesB)
+    ValuesB.push_back(C->getValue());
+
+  // Helper to determine predicate from case values
+  auto GetPredicate = [&](ArrayRef<APInt> ValuesForTrueDest)
+      -> std::optional<ICmpInst::Predicate> {
+    if (ValuesForTrueDest.size() == 1) {
+      if (ValuesForTrueDest[0] == -1)
+        return IsSigned ? ICmpInst::ICMP_SLT : ICmpInst::ICMP_ULT;
+      if (ValuesForTrueDest[0] == 0)
+        return ICmpInst::ICMP_EQ;
+      if (ValuesForTrueDest[0] == 1)
+        return IsSigned ? ICmpInst::ICMP_SGT : ICmpInst::ICMP_UGT;
+    } else if (ValuesForTrueDest.size() == 2) {
+      bool HasNeg1 = false, HasZero = false, HasOne = false;
+      for (const auto &V : ValuesForTrueDest) {
+        if (V == -1) HasNeg1 = true;
+        if (V == 0) HasZero = true;
+        if (V == 1) HasOne = true;
+      }
+      if (HasNeg1 && HasZero)
+        return IsSigned ? ICmpInst::ICMP_SLE : ICmpInst::ICMP_ULE;
+      if (HasZero && HasOne)
+        return IsSigned ? ICmpInst::ICMP_SGE : ICmpInst::ICMP_UGE;
+    } else if (ValuesForTrueDest.size() == 3) {
+      return ICmpInst::ICMP_EQ; // All values
+    }
+    return std::nullopt;
+  };
+
+  // Try CasesA as the "true" destination
+  if (auto Pred = GetPredicate(ValuesA)) {
+    if (ValuesA.size() == 3) {
+      BranchInst::Create(DestA, SI);
+    } else {
+      Value *Cmp = Builder.CreateICmp(*Pred, LHS, RHS, "switch.cmp");
+      BranchInst::Create(DestA, DestB, Cmp, SI);
+    }
+    SI->eraseFromParent();
+    return true;
+  }
+
+  // Try CasesB as the "true" destination
+  if (auto Pred = GetPredicate(ValuesB)) {
+    if (ValuesB.size() == 3) {
+      BranchInst::Create(DestB, SI);
+    } else {
+      Value *Cmp = Builder.CreateICmp(*Pred, LHS, RHS, "switch.cmp");
+      BranchInst::Create(DestB, DestA, Cmp, SI);
+    }
+    SI->eraseFromParent();
+    return true;
+  }
+
+  return false;
+}
