+          if (ValuesForTrueDest[0] == 1)
+            return IsSigned ? ICmpInst::ICMP_SGT : ICmpInst::ICMP_UGT;
+        } else if (ValuesForTrueDest.size() == 2) {
+          bool HasNeg1 = false, HasZero = false, HasOne = false;
+          for (const auto &V : ValuesForTrueDest) {
+            if (V == -1) HasNeg1 = true;
+            if (V == 0) HasZero = true;
+            if (V == 1) HasOne = true;
+          }
+          if (HasNeg1 && HasZero)
