+          return ICmpInst::ICMP_EQ; // Will be replaced with constant true below
+        }
+        return std::nullopt;
+      };
+
+      // Try CasesA as the "true" destination
+      if (auto Pred = GetPredicate(ValuesA, DestA, DestB)) {
+        if (ValuesA.size() == 3) {
+          // All cases go to DestA
+          BranchInst::Create(DestA, SI);
+        } else {
+          Value *Cmp = Builder.CreateICmp(*Pred, LHS, RHS, "switch.cmp");
+          BranchInst::Create(DestA, DestB, Cmp, SI);
+        }
+        SI->eraseFromParent();
+        return true;
+      }
+
+      // Try CasesB as the "true" destination
+      if (auto Pred = GetPredicate(ValuesB, DestB, DestA)) {
+        if (ValuesB.size() == 3) {
+          // All cases go to DestB
+          BranchInst::Create(DestB, SI);
+        } else {
+          Value *Cmp = Builder.CreateICmp(*Pred, LHS, RHS, "switch.cmp");
+          BranchInst::Create(DestB, DestA, Cmp, SI);
+        }
+        SI->eraseFromParent();
+        return true;
+      }
+    }
+  }
+
+  // Figure out if one of the sets of cases form a contiguous range.
+  SmallVectorImpl<ConstantInt *> *ContiguousCases = nullptr;
+  BasicBlock *ContiguousDest = nullptr;
+  BasicBlock *OtherDest = nullptr;
+  if (!CasesA.empty() && casesAreContiguous(CasesA)) {
+    ContiguousCases = &CasesA;
+    ContiguousDest = DestA;
+    OtherDest = DestB;
+  } else if (casesAreContiguous(CasesB)) {
+    ContiguousCases = &CasesB;
+    ContiguousDest = DestB;
+    OtherDest = DestA;
+  } else
+    return false;

