  bool HasDefault =
      !isa<UnreachableInst>(SI->getDefaultDest()->getFirstNonPHIOrDbg());

  auto *BB = SI->getParent();

  // Partition the cases into two sets with different destinations.
  BasicBlock *DestA = HasDefault ? SI->getDefaultDest() : nullptr;
  BasicBlock *DestB = nullptr;
  SmallVector<ConstantInt *, 16> CasesA;
  SmallVector<ConstantInt *, 16> CasesB;

  for (auto Case : SI->cases()) {
    BasicBlock *Dest = Case.getCaseSuccessor();
    if (!DestA)
      DestA = Dest;
    if (Dest == DestA) {
      CasesA.push_back(Case.getCaseValue());
      continue;
    }
    if (!DestB)
      DestB = Dest;
    if (Dest == DestB) {
      CasesB.push_back(Case.getCaseValue());
      continue;
    }
    return false; // More than two destinations.
  }
  if (!DestB)
    return false; // All destinations are the same and the default is unreachable

  assert(DestA && DestB &&
         "Single-destination switch should have been folded.");
  assert(DestA != DestB);
  assert(DestB != SI->getDefaultDest());
  assert(!CasesB.empty() && "There must be non-default cases.");
  assert(!CasesA.empty() || HasDefault);

  // Check if this is a switch on ucmp/scmp intrinsic. ucmp/scmp return -1, 0, or 1
  // depending on whether the first operand is less than, equal to, or greater than
  // the second. If the switch distinguishes these ranges, we can optimize it to a
  // direct comparison of the operands.
  Value *Cond = SI->getCondition();
  if (auto *II = dyn_cast<IntrinsicInst>(Cond)) {
    Intrinsic::ID IID = II->getIntrinsicID();
    if ((IID == Intrinsic::ucmp || IID == Intrinsic::scmp) &&
        CasesA.size() + CasesB.size() == SI->getNumCases()) {
      // ucmp/scmp can only return -1, 0, or 1. Check if we have cases that
      // distinguish between these three values across two destinations.
      bool IsSigned = (IID == Intrinsic::scmp);
      Value *LHS = II->getOperand(0);
      Value *RHS = II->getOperand(1);

      // Collect all case values for each destination
      SmallVector<APInt, 3> ValuesA, ValuesB;
      for (auto *C : CasesA)
        ValuesA.push_back(C->getValue());
      for (auto *C : CasesB)
        ValuesB.push_back(C->getValue());

      // Check if one destination has exactly one value and the other has the rest.
      // Valid scenarios: one dest has {-1}, {0}, or {1}; other has the other two values.
      // Or: one dest has {-1, 0} and other has {1}, etc.
      auto GetPredicate = [&](ArrayRef<APInt> ValuesForTrueDest,
                              BasicBlock *TrueDest,
                              BasicBlock *FalseDest) -> std::optional<ICmpInst::Predicate> {
        if (ValuesForTrueDest.size() == 1) {
          if (ValuesForTrueDest[0] == -1)
            return IsSigned ? ICmpInst::ICMP_SLT : ICmpInst::ICMP_ULT;
          if (ValuesForTrueDest[0] == 0)
            return ICmpInst::ICMP_EQ;
          if (ValuesForTrueDest[0] == 1)
            return IsSigned ? ICmpInst::ICMP_SGT : ICmpInst::ICMP_UGT;
        } else if (ValuesForTrueDest.size() == 2) {
          bool HasNeg1 = false, HasZero = false, HasOne = false;
          for (const auto &V : ValuesForTrueDest) {
            if (V == -1) HasNeg1 = true;
            if (V == 0) HasZero = true;
            if (V == 1) HasOne = true;
          }
          if (HasNeg1 && HasZero)
            return IsSigned ? ICmpInst::ICMP_SLE : ICmpInst::ICMP_ULE;
          if (HasZero && HasOne)
            return IsSigned ? ICmpInst::ICMP_SGE : ICmpInst::ICMP_UGE;
        } else if (ValuesForTrueDest.size() == 3) {
          // All values go to true dest
          return ICmpInst::ICMP_EQ; // Will be replaced with constant true below
        }
        return std::nullopt;
